const e=JSON.parse('{"key":"v-6744990c","path":"/%E8%AF%81%E5%88%B8%E4%BA%A4%E6%98%93/%E9%81%93%E6%B0%8F%E7%90%86%E8%AE%BA%EF%BC%88%E5%A4%A9%E6%B4%A5%E7%A4%BE%E7%A7%91%E7%89%88%EF%BC%89/02-%E9%81%93%E6%B0%8F%E7%90%86%E8%AE%BA%E4%BA%8C.html","title":"道氏理论二","lang":"zh-CN","frontmatter":{"date":"2024-01-17T00:00:00.000Z","category":["证券交易"],"tag":["道氏理论"],"order":2,"description":"道氏理论二 道氏理论定义的三种运动 平均价格指数通常包括三种类型的运动，这三种运动或许会在同一时点存在。首先最为重要的就是主要运动：它代表着股市整体向上或向下的主要方向，也就是众所周知的牛市或熊市，其持续时间或许要数年之久。处于第二位的是次级运动，它是看起来最具有欺骗性的运动。次级运动表现为牛市之中的回调行情，以及熊市之中的反弹行情。这些次级运动通常会持续三周到几个月之久。处于第三位的，通常也属于不太重要的运动，那就是平均价格指数的日间波动。 令每一位驾驶员终生难忘的事，莫过于第一次驾驶时脑袋和手脚之间出现的错乱状况。坐在身边的陪练，苦口婆心地讲解如何在瞬间同时执行看路况、踩刹车等动作。然而随着驾驶经验的增多，油门和刹车的使用与看路况的动作逐渐合而为一，并且慢慢地变成了习惯。以此类推，初学者第一次接触道氏理论所说的三种运动时，难免也会存在类似的错乱状况。但是如果假以时日他们对三种价格运动的把握技巧，也会慢慢做到得心应手。次级运动只会让市场趋势出现暂时变化，这与刹车对汽车的效果完全相同：它们都是对超速运行施加的有效控制。至于汽车油门，它对于推动汽车减速和加速，效力可以与价格运动中的日间波动相提并论。有时候股票市场日间波动与市场主要运动或次级运动的方向相同，有时候则相反。","head":[["meta",{"property":"og:url","content":"https://mister-hope.github.io/%E8%AF%81%E5%88%B8%E4%BA%A4%E6%98%93/%E9%81%93%E6%B0%8F%E7%90%86%E8%AE%BA%EF%BC%88%E5%A4%A9%E6%B4%A5%E7%A4%BE%E7%A7%91%E7%89%88%EF%BC%89/02-%E9%81%93%E6%B0%8F%E7%90%86%E8%AE%BA%E4%BA%8C.html"}],["meta",{"property":"og:site_name","content":"Journey of Growth"}],["meta",{"property":"og:title","content":"道氏理论二"}],["meta",{"property":"og:description","content":"道氏理论二 道氏理论定义的三种运动 平均价格指数通常包括三种类型的运动，这三种运动或许会在同一时点存在。首先最为重要的就是主要运动：它代表着股市整体向上或向下的主要方向，也就是众所周知的牛市或熊市，其持续时间或许要数年之久。处于第二位的是次级运动，它是看起来最具有欺骗性的运动。次级运动表现为牛市之中的回调行情，以及熊市之中的反弹行情。这些次级运动通常会持续三周到几个月之久。处于第三位的，通常也属于不太重要的运动，那就是平均价格指数的日间波动。 令每一位驾驶员终生难忘的事，莫过于第一次驾驶时脑袋和手脚之间出现的错乱状况。坐在身边的陪练，苦口婆心地讲解如何在瞬间同时执行看路况、踩刹车等动作。然而随着驾驶经验的增多，油门和刹车的使用与看路况的动作逐渐合而为一，并且慢慢地变成了习惯。以此类推，初学者第一次接触道氏理论所说的三种运动时，难免也会存在类似的错乱状况。但是如果假以时日他们对三种价格运动的把握技巧，也会慢慢做到得心应手。次级运动只会让市场趋势出现暂时变化，这与刹车对汽车的效果完全相同：它们都是对超速运行施加的有效控制。至于汽车油门，它对于推动汽车减速和加速，效力可以与价格运动中的日间波动相提并论。有时候股票市场日间波动与市场主要运动或次级运动的方向相同，有时候则相反。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2024-02-04T15:27:55.000Z"}],["meta",{"property":"article:author","content":"Mr.G"}],["meta",{"property":"article:tag","content":"道氏理论"}],["meta",{"property":"article:published_time","content":"2024-01-17T00:00:00.000Z"}],["meta",{"property":"article:modified_time","content":"2024-02-04T15:27:55.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"道氏理论二\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2024-01-17T00:00:00.000Z\\",\\"dateModified\\":\\"2024-02-04T15:27:55.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"Mr.G\\",\\"url\\":\\"https://mister-hope.com\\"}]}"]]},"headers":[{"level":2,"title":"道氏理论定义的三种运动","slug":"道氏理论定义的三种运动","link":"#道氏理论定义的三种运动","children":[]},{"level":2,"title":"主要运动","slug":"主要运动","link":"#主要运动","children":[]},{"level":2,"title":"熊市","slug":"熊市","link":"#熊市","children":[]},{"level":2,"title":"牛市","slug":"牛市","link":"#牛市","children":[]},{"level":2,"title":"次级运动","slug":"次级运动","link":"#次级运动","children":[]}],"git":{"createdTime":1707060475000,"updatedTime":1707060475000,"contributors":[{"name":"gm-hacker","email":"gm-hacker@qq.com","commits":1}]},"readingTime":{"minutes":56.7,"words":17009},"filePathRelative":"证券交易/道氏理论（天津社科版）/02-道氏理论二.md","localizedDate":"2024年1月17日","excerpt":"<h1> 道氏理论二</h1>\\n<h2> 道氏理论定义的三种运动</h2>\\n<p>平均价格指数通常包括三种类型的运动，这三种运动或许会在同一时点存在。首先最为重要的就是主要运动：它代表着股市整体向上或向下的主要方向，也就是众所周知的牛市或熊市，其持续时间或许要数年之久。处于第二位的是次级运动，它是看起来最具有欺骗性的运动。次级运动表现为牛市之中的回调行情，以及熊市之中的反弹行情。这些次级运动通常会持续三周到几个月之久。处于第三位的，通常也属于不太重要的运动，那就是平均价格指数的日间波动。</p>\\n<p>令每一位驾驶员终生难忘的事，莫过于第一次驾驶时脑袋和手脚之间出现的错乱状况。坐在身边的陪练，苦口婆心地讲解如何在瞬间同时执行看路况、踩刹车等动作。然而随着驾驶经验的增多，油门和刹车的使用与看路况的动作逐渐合而为一，并且慢慢地变成了习惯。以此类推，初学者第一次接触道氏理论所说的三种运动时，难免也会存在类似的错乱状况。但是如果假以时日他们对三种价格运动的把握技巧，也会慢慢做到得心应手。次级运动只会让市场趋势出现暂时变化，这与刹车对汽车的效果完全相同：它们都是对超速运行施加的有效控制。至于汽车油门，它对于推动汽车减速和加速，效力可以与价格运动中的日间波动相提并论。有时候股票市场日间波动与市场主要运动或次级运动的方向相同，有时候则相反。</p>","autoDesc":true}');export{e as data};
